const Dev = "ASSET_ID_START_MET_36 ";   // bv. "HVAC" of "DOOR_KOELCEL_01"
const port = msg.fport || msg.port || 0;

const IDS = {
    // Metrics
    door_status: 6101,          // 1 = OPEN, 0 = GESLOTEN
    alarm: 6102,                // 1 = alarm actief, 0 = geen alarm
    tdc_flag: 6111,             // 1 = periodieke uplink, 0 = event uplink
    open_count: 6112,           // aantal open-events
    last_open_duration: 6113,   // seconden
    sensor_timestamp: 6114,     // ruwe sensor timestamp
    battery: 7200,              // batterijspanning in V
    snr: 5400,
    rssi: 5500,
    spreadFactor: 5200,
    frequency: 5300,
    firmware_version_num: 1010, // bv. 1.0.0 => 10000
    frequency_band_code: 1011,  // 1 = EU868, etc.

    // Events
    door_event: 1003,           // "OPEN" / "GESLOTEN"
    alarm_event: 1004           // "OPEN_TOO_LONG"
};

// -------------------------
// Payload -> Buffer
// -------------------------
var buf = (typeof msg.payload === "string")
    ? Buffer.from(msg.payload, "base64")
    : msg.payload;

if (!Buffer.isBuffer(buf) || buf.length === 0) {
    node.error("Invalid payload", msg);
    return null;
}

// -------------------------
// Helpers
// -------------------------
function readUInt24BE(buffer, offset) {
    if (offset + 3 > buffer.length) return null;
    return (buffer[offset] << 16) | (buffer[offset + 1] << 8) | buffer[offset + 2];
}

function readUInt32BE(buffer, offset) {
    if (offset + 4 > buffer.length) return null;
    return (buffer[offset] * 0x1000000) +
        ((buffer[offset + 1] << 16) | (buffer[offset + 2] << 8) | buffer[offset + 3]);
}

function pushMD(arr, id, val) {
    if (val !== null && val !== undefined && !Number.isNaN(val)) {
        arr.push({ Id: id, Val: val });
    }
}

function pushED(arr, id, val) {
    if (val !== null && val !== undefined) {
        arr.push({ Id: id, Val: val });
    }
}

function freqBandToCode(bandByte) {
    switch (bandByte) {
        case 0x01: return 1;   // EU868
        case 0x02: return 2;   // US915
        case 0x03: return 3;   // IN865
        case 0x04: return 4;   // AU915
        case 0x05: return 5;   // KZ865
        case 0x06: return 6;   // RU864
        case 0x07: return 7;   // AS923
        case 0x08: return 8;   // AS923_1
        case 0x09: return 9;   // AS923_2
        case 0x0A: return 10;  // AS923_3
        case 0x0B: return 11;  // CN470
        case 0x0C: return 12;  // EU433
        case 0x0D: return 13;  // KR920
        case 0x0E: return 14;  // MA869
        default: return 0;
    }
}

// -------------------------
// Vorige status bewaren
// zodat ED enkel events geeft
// bij echte wijzigingen
// -------------------------
var prevDoor = context.get("lds03a_prevDoor");
var prevAlarm = context.get("lds03a_prevAlarm");

// -------------------------
// Basis output
// -------------------------
var mid = global.get("mid") || 0;

var result = {
    MID: mid,
    D: [{
        Dev: Dev,
        TS: msg.time ? new Date(msg.time).toISOString() : new Date().toISOString(),
        ED: [],
        MD: []
    }]
};

var ed = result.D[0].ED;
var md = result.D[0].MD;

// -------------------------
// fPort 2 = realtime status
// Officiële decoder:
// byte0 bit0 = door
// byte0 bit1 = alarm
// byte0 bit2 = TDC flag
// bytes1-3 = open count
// bytes4-6 = last open duration
// bytes7-10 = timestamp
// -------------------------
if (port === 2) {
    if (buf.length < 11) {
        node.error("Invalid LDS03A realtime payload length for fPort 2", msg);
        return null;
    }

    var flags = buf[0];
    var doorStatus = (flags & 0x01) ? 1 : 0;   // 1 = OPEN, 0 = GESLOTEN
    var alarm = (flags & 0x02) ? 1 : 0;
    var tdcFlag = (flags & 0x04) ? 1 : 0;

    var openCount = readUInt24BE(buf, 1);
    var lastOpenDuration = readUInt24BE(buf, 4);
    var sensorTimestamp = readUInt32BE(buf, 7);

    // Metrics
    pushMD(md, IDS.door_status, doorStatus);
    pushMD(md, IDS.alarm, alarm);
    pushMD(md, IDS.tdc_flag, tdcFlag);
    pushMD(md, IDS.open_count, openCount);
    pushMD(md, IDS.last_open_duration, lastOpenDuration);
    pushMD(md, IDS.sensor_timestamp, sensorTimestamp);

    // Event alleen bij echte statuswissel
    if (prevDoor === undefined || prevDoor === null || prevDoor !== doorStatus) {
        pushED(ed, IDS.door_event, doorStatus === 1 ? "OPEN" : "GESLOTEN");
    }

    // Alarm event alleen bij overgang 0 -> 1
    if (prevAlarm !== undefined && prevAlarm !== null && prevAlarm === 0 && alarm === 1) {
        pushED(ed, IDS.alarm_event, "OPEN_TOO_LONG");
    }

    context.set("lds03a_prevDoor", doorStatus);
    context.set("lds03a_prevAlarm", alarm);
}

// -------------------------
// fPort 5 = device status
// Officiële decoder:
// bytes[1..2] firmware
// bytes[3] frequency band
// bytes[5..6] battery
// -------------------------
else if (port === 5) {
    if (buf.length < 7) {
        node.error("Invalid LDS03A device status payload length for fPort 5", msg);
        return null;
    }

    var battery = ((buf[5] << 8) | buf[6]) / 1000;
    var bandCode = freqBandToCode(buf[3]);

    var fwMajor = (buf[1] & 0x0f);
    var fwMinor = ((buf[2] >> 4) & 0x0f);
    var fwPatch = (buf[2] & 0x0f);
    var fwNum = (fwMajor * 10000) + (fwMinor * 100) + fwPatch;

    pushMD(md, IDS.battery, Math.round(battery * 1000) / 1000);
    pushMD(md, IDS.frequency_band_code, bandCode);
    pushMD(md, IDS.firmware_version_num, fwNum);
}

// -------------------------
// Andere fPorts voorlopig negeren
// -------------------------
else {
    node.warn("Unsupported or not yet mapped fPort for LDS03A: " + port);
}

// -------------------------
// Extra radio info
// -------------------------
[
    ["snr", IDS.snr],
    ["rssi", IDS.rssi],
    ["freq", IDS.frequency]
].forEach(function (item) {
    var key = item[0];
    var id = item[1];
    if (msg[key] !== undefined) {
        pushMD(md, id, parseFloat(msg[key]));
    }
});

if (msg.dr && msg.dr.spreadFactor !== undefined) {
    pushMD(md, IDS.spreadFactor, parseFloat(msg.dr.spreadFactor));
}

// -------------------------
// MID ophogen
// -------------------------
global.set("mid", mid + 1);

// Output
msg.payload = result;
return msg;
